:root {
  --base-font-size: 1rem;
  --base-line-height: 1.6;
  --spacing-unit: calc(var(--base-font-size) * var(--base-line-height));
}

body {
  font-family: 'Inter', sans-serif;
  font-size: var(--base-font-size);
  line-height: var(--base-line-height);
}

h1, h2, h3, h4, h5, h6, p, ul, ol, blockquote {
  margin-bottom: var(--spacing-unit);
}

/* Example of scaling line-height for headings */
h1 {
  font-size: 3rem;
  line-height: 1.2; /* Tighter line-height for large headings */
  margin-bottom: calc(var(--spacing-unit) * 1.5); /* Adjust spacing */
}

h2 {
  font-size: 2rem;
  line-height: 1.3;
  margin-bottom: var(--spacing-unit);
}
